[{"pg_get_functiondef":"CREATE OR REPLACE FUNCTION public.admin_set_credits(target_user_id uuid, new_credits integer, is_delta boolean DEFAULT false)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  caller_role text;
  current_tokens integer;
  final_balance integer;
BEGIN
  SELECT role INTO caller_role FROM profiles WHERE id = auth.uid();
  IF caller_role IS DISTINCT FROM 'admin' THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  IF is_delta THEN
    SELECT tokens INTO current_tokens FROM profiles WHERE id = target_user_id;
    IF current_tokens IS NULL THEN
      RAISE EXCEPTION 'User not found';
    END IF;
    final_balance := GREATEST(0, current_tokens + new_credits);
  ELSE
    final_balance := new_credits;
  END IF;

  UPDATE profiles SET tokens = final_balance, updated_at = now()
  WHERE id = target_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'User not found';
  END IF;

  RETURN final_balance;
END;
$function$
"}]
